            Object response = null;
            if (Helpers.isTrue(uta))
            {
                response = (this.utaGetAssetCurrencies(parameters)).join();
            } else
            {
                //
                //    {
                //        "code":"200000",
                //        "data":[
                //           {
                //              "currency":"CSP",
                //              "name":"CSP",
                //              "fullName":"Caspian",
                //              "precision":8,
                //              "confirms":null,
                //              "contractAddress":null,
                //              "isMarginEnabled":false,
                //              "isDebitEnabled":false,
                //              "chains":[
                //                 {
                //                    "chainName":"ERC20",
                //                    "chainId": "eth"
                //                    "withdrawalMinSize":"2999",
                //                    "depositMinSize":null,
                //                    "withdrawFeeRate":"0",
                //                    "withdrawalMinFee":"2999",
                //                    "isWithdrawEnabled":false,
                //                    "isDepositEnabled":false,
                //                    "confirms":12,
                //                    "preConfirms":12,
                //                    "withdrawPrecision": 8,
                //                    "maxWithdraw": null,
                //                    "maxDeposit": null,
                //                    "needTag": false,
                //                    "contractAddress":"0xa6446d655a0c34bc4f05042ee88170d056cbaf45",
                //                    "depositFeeRate": "0.001", // present for some currencies/networks
                //                 }
                //              ]
                //           },
                //        ]
                //    }
                //
                response = (this.publicGetCurrencies(parameters)).join();
            }
            Object currenciesData = this.safeList(response, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
