    public Object typeToTradeType(Object type)
    {
        Object tradeTypes = new java.util.HashMap<String, Object>() {{
            put( "spot", "SPOT" );
            put( "margin", "MARGIN" );
            put( "swap", "FUTURES" );
        }};
        if (Helpers.isTrue(Helpers.isEqual(type, null)))
        {
            return null;
        }
        return this.safeString(tradeTypes, type, type);
    }

    /**
     * @method
     * @name kucoin#fetchTickers
     * @description fetches price tickers for multiple markets, statistical information calculated over the past 24 hours for each market
     * @see https://www.kucoin.com/docs-new/rest/spot-trading/market-data/get-all-tickers
     * @see https://www.kucoin.com/docs-new/rest/futures-trading/market-data/get-all-tickers
     * @see https://www.kucoin.com/docs-new/rest/ua/get-ticker
     * @param {string[]|undefined} [symbols] unified symbols of the markets to fetch the ticker for, all market tickers are returned if not assigned
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {boolean} [params.uta] set to true for the unified trading account (uta), defaults to false
     * @param {string} [params.type] spot or swap (default is spot)
     * @param {string} [params.method] *swap only* the method to use, futuresPublicGetContractsActive or futuresPublicGetAllTickers (default is futuresPublicGetContractsActive)
     * @returns {object} a dictionary of [ticker structures]{@link https://docs.ccxt.com/?id=ticker-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchTickers(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbols = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object request = new java.util.HashMap<String, Object>() {{}};
            symbols = this.marketSymbols(symbols, null, true, true);
            Object uta = false;
            var utaparametersVariable = this.handleOptionAndParams(parameters, "fetchTickers", "uta", uta);
            uta = ((java.util.List<Object>) utaparametersVariable).get(0);
            parameters = ((java.util.List<Object>) utaparametersVariable).get(1);
            Object tradeType = this.safeString(parameters, "tradeType");
            Object firstMarket = null;
            if (Helpers.isTrue(!Helpers.isEqual(symbols, null)))
            {
                Object firstSymbol = this.safeString(symbols, 0);
                if (Helpers.isTrue(!Helpers.isEqual(firstSymbol, null)))
                {
                    firstMarket = this.market(firstSymbol);
                }
            }
            Object type = null;
            var typeparametersVariable = this.handleMarketTypeAndParams("fetchTickers", firstMarket, parameters);
            type = ((java.util.List<Object>) typeparametersVariable).get(0);
            parameters = ((java.util.List<Object>) typeparametersVariable).get(1);
            Object response = null;
            if (Helpers.isTrue(Helpers.isTrue((!Helpers.isEqual(tradeType, null))) || Helpers.isTrue(uta)))
            {
                if (Helpers.isTrue(Helpers.isEqual(tradeType, null)))
                {
                    Helpers.addElementToObject(request, "tradeType", this.typeToTradeType(type));
                }
                response = (this.utaGetMarketTicker(this.extend(request, parameters))).join();
            } else if (Helpers.isTrue(Helpers.isTrue((!Helpers.isEqual(type, "spot"))) && Helpers.isTrue((!Helpers.isEqual(type, "margin")))))
            {
                return (this.fetchContractTickers(symbols, parameters)).join();
            } else
            {
                response = (this.publicGetMarketAllTickers(parameters)).join();
            }
            Object data = this.safeDict(response, "data", new java.util.HashMap<String, Object>() {{}});
            Object tickers = this.safeList2(data, "ticker", "list", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object time = this.safeInteger2(data, "time", "ts");
            Object result = new java.util.HashMap<String, Object>() {{}};
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(tickers)); i++)
            {
                Helpers.addElementToObject(Helpers.GetValue(tickers, i), "time", time);
                Object ticker = this.parseSpotOrUtaTicker(Helpers.GetValue(tickers, i));
                Object symbol = this.safeString(ticker, "symbol");
                if (Helpers.isTrue(!Helpers.isEqual(symbol, null)))
                {
                    Helpers.addElementToObject(result, symbol, ticker);
                }
            }
            return this.filterByArrayTickers(result, "symbol", symbols);
        });

    }

