    /**
     * @method
     * @name kucoin#fetchMyTrades
     * @see https://www.kucoin.com/docs-new/rest/spot-trading/orders/get-trade-history
     * @see https://www.kucoin.com/docs-new/rest/margin-trading/orders/get-trade-history
     * @see https://www.kucoin.com/docs-new/rest/ua/get-trade-history
     * @description fetch all trades made by the user
     * @param {string} symbol unified market symbol
     * @param {int} [since] the earliest time in ms to fetch trades for
     * @param {int} [limit] the maximum number of trades structures to retrieve
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {boolean} [params.paginate] default false, when true will automatically paginate by calling this endpoint multiple times. See in the docs all the [availble parameters](https://github.com/ccxt/ccxt/wiki/Manual#pagination-params)
     * @param {string} [params.type] 'spot' or 'swap', used if symbol is not provided (default is 'spot')
     * Check fetchMySpotTrades() and fetchMyContractTrades() for more details on the extra parameters that can be used in params
     * @returns {Trade[]} a list of [trade structures]{@link https://docs.ccxt.com/?id=trade-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchMyTrades(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbol = Helpers.getArg(optionalArgs, 0, null);
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object marketType = null;
            Object market = null;
            if (Helpers.isTrue(!Helpers.isEqual(symbol, null)))
            {
                market = this.market(symbol);
            }
            var marketTypeparametersVariable = this.handleMarketTypeAndParams("fetchMyTrades", market, parameters);
            marketType = ((java.util.List<Object>) marketTypeparametersVariable).get(0);
            parameters = ((java.util.List<Object>) marketTypeparametersVariable).get(1);
            Object uta = (this.isUTAEnabled()).join();
            var utaparametersVariable = this.handleOptionAndParams(parameters, "fetchMyTrades", "uta", uta);
            uta = ((java.util.List<Object>) utaparametersVariable).get(0);
            parameters = ((java.util.List<Object>) utaparametersVariable).get(1);
            if (Helpers.isTrue(uta))
            {
                final Object finalMarketType = marketType;
                parameters = this.extend(parameters, new java.util.HashMap<String, Object>() {{
                    put( "marketType", finalMarketType );
                }});
                return (this.fetchMyUtaTrades(symbol, since, limit, parameters)).join();
            }
            if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(marketType, "spot"))) || Helpers.isTrue((Helpers.isEqual(marketType, "margin")))))
            {
                return (this.fetchMySpotTrades(symbol, since, limit, parameters)).join();
            } else
            {
                return (this.fetchMyContractTrades(symbol, since, limit, parameters)).join();
            }
        });

    }

    /**
     * @method
     * @name kucoin#fetchMySpotTrades
     * @see https://www.kucoin.com/docs-new/rest/spot-trading/orders/get-trade-history
     * @see https://www.kucoin.com/docs-new/rest/margin-trading/orders/get-trade-history
     * @description fetch all spot trades made by the user
     * @param {string} symbol unified market symbol
     * @param {int} [since] the earliest time in ms to fetch trades for
     * @param {int} [limit] the maximum number of trades structures to retrieve
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {int} [params.until] the latest time in ms to fetch entries for
     * @param {bool} [params.hf] false, // true for hf order
     * @param {string} [params.marginMode] 'cross' or 'isolated', only for margin trades
     * @param {boolean} [params.paginate] default false, when true will automatically paginate by calling this endpoint multiple times. See in the docs all the [availble parameters](https://github.com/ccxt/ccxt/wiki/Manual#pagination-params)
     * @returns {Trade[]} a list of [trade structures]{@link https://docs.ccxt.com/?id=trade-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchMySpotTrades(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbol = Helpers.getArg(optionalArgs, 0, null);
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object paginate = false;
            var paginateparametersVariable = this.handleOptionAndParams(parameters, "fetchMyTrades", "paginate");
            paginate = ((java.util.List<Object>) paginateparametersVariable).get(0);
            parameters = ((java.util.List<Object>) paginateparametersVariable).get(1);
            if (Helpers.isTrue(paginate))
            {
                return (this.fetchPaginatedCallDynamic("fetchMyTrades", symbol, since, limit, parameters)).join();
            }
            Object request = new java.util.HashMap<String, Object>() {{}};
            Object hf = null;
            var hfparametersVariable = this.handleHfAndParams(parameters);
            hf = ((java.util.List<Object>) hfparametersVariable).get(0);
            parameters = ((java.util.List<Object>) hfparametersVariable).get(1);
            Object marginMode = null;
            var marginModeparametersVariable = this.handleMarginModeAndParams("fetchMyTrades", parameters);
            marginMode = ((java.util.List<Object>) marginModeparametersVariable).get(0);
            parameters = ((java.util.List<Object>) marginModeparametersVariable).get(1);
            Object isMargin = !Helpers.isEqual(marginMode, null);
            if (Helpers.isTrue(isMargin))
            {
                hf = true;
                Helpers.addElementToObject(request, "tradeType", ((Helpers.isTrue((Helpers.isEqual(marginMode, null))))) ? null : this.safeString(Helpers.GetValue(this.options, "marginModes"), marginMode, marginMode));
            }
            if (Helpers.isTrue(Helpers.isTrue(hf) && Helpers.isTrue(Helpers.isEqual(symbol, null))))
            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " fetchMyTrades() requires a symbol parameter for hf or margin orders")) ;
            }
            Object market = null;
            if (Helpers.isTrue(!Helpers.isEqual(symbol, null)))
            {
                market = this.market(symbol);
                Helpers.addElementToObject(request, "symbol", Helpers.GetValue(market, "id"));
            }
            Object method = Helpers.GetValue(this.options, "fetchMyTradesMethod");
            Object parseResponseData = false;
            Object response = null;
            var requestparametersVariable = this.handleUntilOption("endAt", request, parameters);
            request = ((java.util.List<Object>) requestparametersVariable).get(0);
            parameters = ((java.util.List<Object>) requestparametersVariable).get(1);
            if (Helpers.isTrue(hf))
            {
                // does not return trades earlier than 2019-02-18T00:00:00Z
                if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
                {
                    Helpers.addElementToObject(request, "limit", limit);
                }
                if (Helpers.isTrue(!Helpers.isEqual(since, null)))
                {
                    // only returns trades up to one week after the since param
                    Helpers.addElementToObject(request, "startAt", since);
                }
                if (Helpers.isTrue(isMargin))
                {
                    response = (this.privateGetHfMarginFills(this.extend(request, parameters))).join();
                } else
                {
                    response = (this.privateGetHfFills(this.extend(request, parameters))).join();
                }
            } else if (Helpers.isTrue(Helpers.isEqual(method, "private_get_fills")))
            {
                // does not return trades earlier than 2019-02-18T00:00:00Z
                if (Helpers.isTrue(!Helpers.isEqual(since, null)))
                {
                    // only returns trades up to one week after the since param
                    Helpers.addElementToObject(request, "startAt", since);
                }
                response = (this.privateGetFills(this.extend(request, parameters))).join();
            } else if (Helpers.isTrue(Helpers.isEqual(method, "private_get_limit_fills")))
            {
                // does not return trades earlier than 2019-02-18T00:00:00Z
                // takes no params
                // only returns first 1000 trades (not only "in the last 24 hours" as stated in the docs)
                parseResponseData = true;
                response = (this.privateGetLimitFills(this.extend(request, parameters))).join();
            } else
            {
                throw new ExchangeError((String)Helpers.add(this.id, " fetchMyTradesMethod() invalid method")) ;
            }
            //
            //     {
            //         "currentPage": 1,
            //         "pageSize": 50,
            //         "totalNum": 1,
            //         "totalPage": 1,
            //         "items": [
            //             {
            //                 "symbol":"BTC-USDT",       // symbol
            //                 "tradeId":"5c35c02709e4f67d5266954e",        // trade id
            //                 "orderId":"5c35c02703aa673ceec2a168",        // order id
            //                 "counterOrderId":"5c1ab46003aa676e487fa8e3", // counter order id
            //                 "side":"buy",              // transaction direction,include buy and sell
            //                 "liquidity":"taker",       // include taker and maker
            //                 "forceTaker":true,         // forced to become taker
            //                 "price":"0.083",           // order price
            //                 "size":"0.8424304",        // order quantity
            //                 "funds":"0.0699217232",    // order funds
            //                 "fee":"0",                 // fee
            //                 "feeRate":"0",             // fee rate
            //                 "feeCurrency":"USDT",      // charge fee currency
            //                 "stop":"",                 // stop type
            //                 "type":"limit",            // order type, e.g. limit, market, stop_limit.
            //                 "createdAt":1547026472000  // time
            //             },
            //             //------------------------------------------------------
            //             // v1 (historical) trade response structure
            //             {
            //                 "symbol": "SNOV-ETH",
            //                 "dealPrice": "0.0000246",
            //                 "dealValue": "0.018942",
            //                 "amount": "770",
            //                 "fee": "0.00001137",
            //                 "side": "sell",
            //                 "createdAt": 1540080199
            //                 "id":"5c4d389e4c8c60413f78e2e5",
            //             }
            //         ]
            //     }
            //
            Object data = this.safeDict(response, "data", new java.util.HashMap<String, Object>() {{}});
            Object trades = null;
            if (Helpers.isTrue(parseResponseData))
            {
                trades = data;
            } else
            {
                trades = this.safeList(data, "items", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            }
            return this.parseTrades(trades, market, since, limit);
        });

    }

