    public Object calculateRateLimiterCost(Object api, Object method, Object path, Object parameters, Object... optionalArgs)
    {
        Object config = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
        Object versions = this.safeDict(this.options, "versions", new java.util.HashMap<String, Object>() {{}});
        Object apiVersions = this.safeDict(versions, api, new java.util.HashMap<String, Object>() {{}});
        Object methodVersions = this.safeDict(apiVersions, method, new java.util.HashMap<String, Object>() {{}});
        Object defaultVersion = this.safeString(methodVersions, path, Helpers.GetValue(this.options, "version"));
        Object version = this.safeString(parameters, "version", defaultVersion);
        if (Helpers.isTrue(Helpers.isTrue(Helpers.isEqual(version, "v3")) && Helpers.isTrue((Helpers.inOp(config, "v3")))))
        {
            return Helpers.GetValue(config, "v3");
        } else if (Helpers.isTrue(Helpers.isTrue(Helpers.isEqual(version, "v2")) && Helpers.isTrue((Helpers.inOp(config, "v2")))))
        {
            return Helpers.GetValue(config, "v2");
        } else if (Helpers.isTrue(Helpers.isTrue(Helpers.isEqual(version, "v1")) && Helpers.isTrue((Helpers.inOp(config, "v1")))))
        {
            return Helpers.GetValue(config, "v1");
        }
        return this.safeValue(config, "cost", 1);
    }

    public Object parseBorrowRate(Object info, Object... optionalArgs)
    {
        //
        //     {
        //         "tradeId": "62db2dcaff219600012b56cd",
        //         "currency": "USDT",
        //         "size": "10",
        //         "dailyIntRate": "0.00003",
        //         "term": 7,
        //         "timestamp": 1658531274508488480
        //     },
        //
        //     {
        //         "createdAt": 1697783812257,
        //         "currency": "XMR",
        //         "interestAmount": "0.1",
        //         "dayRatio": "0.001"
        //     }
        //
        // fetchCrossBorrowRate
        //     {
        //         "currentRateHourly": "0.00000353",
        //         "currentRateDaily": "0.00008466",
        //         "borrowLimitTotal": "600.00000000000000000000",
        //         "borrowLimitTotalHold": "0.00000000000000000000",
        //         "borrowLimitHold": "0.00000000000000000000",
        //         "interestFreeBorrowLimit": "0.60000000000000000000"
        //     }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object timestampId = this.safeString2(info, "createdAt", "timestamp");
        Object timestamp = this.milliseconds();
        if (Helpers.isTrue(!Helpers.isEqual(timestampId, null)))
        {
            timestamp = this.parseToInt(Helpers.slice(timestampId, 0, 13));
        }
        Object currencyId = this.safeString(info, "currency");
        final Object finalTimestamp = timestamp;
        return new java.util.HashMap<String, Object>() {{
            put( "currency", KucoinCore.this.safeCurrencyCode(currencyId, currency) );
            put( "rate", KucoinCore.this.safeNumberN(info, new java.util.ArrayList<Object>(java.util.Arrays.asList("dailyIntRate", "dayRatio", "currentRateDaily"))) );
            put( "period", 86400000 );
            put( "timestamp", finalTimestamp );
            put( "datetime", KucoinCore.this.iso8601(finalTimestamp) );
            put( "info", info );
        }};
    }

