    public Object parseFundingRate(Object data, Object... optionalArgs)
    {
        // uta
        //     {
        //         "symbol": ".ETHUSDTMFPI8H",
        //         "nextFundingRate": -3.4E-5,
        //         "fundingTime": 1776700800000,
        //         "fundingRateCap": 0.00375,
        //         "fundingRateFloor": -0.00375,
        //         "currentGranularity": 28800000,
        //         "newGranularity": 28800000,
        //         "newGranularityStartTime": 1750147200000
        //     }
        //
        // futures
        //     {
        //         "symbol": ".ETHUSDTMFPI8H",
        //         "granularity": 28800000,
        //         "timePoint": 1776672000000,
        //         "value": -3.2E-5,
        //         "dailyInterestRate": 3.0E-4,
        //         "fundingRateCap": 0.00375,
        //         "fundingRateFloor": -0.00375,
        //         "period": 1,
        //         "fundingTime": 1776700800000
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object fundingTimestamp = this.safeInteger(data, "fundingTime");
        Object previousFundingTimestamp = this.safeInteger(data, "timePoint");
        Object nextFundingTimestamp = this.safeInteger(data, "newGranularityStartTime");
        Object marketId = this.safeString(data, "symbol");
        Object granularity = this.safeString2(data, "granularity", "currentGranularity");
        return new java.util.HashMap<String, Object>() {{
            put( "info", data );
            put( "symbol", KucoinCore.this.safeSymbol(marketId, market, null, "contract") );
            put( "markPrice", null );
            put( "indexPrice", null );
            put( "interestRate", KucoinCore.this.safeNumber(data, "dailyInterestRate") );
            put( "estimatedSettlePrice", null );
            put( "timestamp", null );
            put( "datetime", null );
            put( "fundingRate", KucoinCore.this.safeNumber2(data, "nextFundingRate", "value") );
            put( "fundingTimestamp", fundingTimestamp );
            put( "fundingDatetime", KucoinCore.this.iso8601(fundingTimestamp) );
            put( "nextFundingRate", null );
            put( "nextFundingTimestamp", nextFundingTimestamp );
            put( "nextFundingDatetime", KucoinCore.this.iso8601(nextFundingTimestamp) );
            put( "previousFundingRate", null );
            put( "previousFundingTimestamp", previousFundingTimestamp );
            put( "previousFundingDatetime", KucoinCore.this.iso8601(previousFundingTimestamp) );
            put( "interval", KucoinCore.this.parseFundingInterval(granularity) );
        }};
    }

    public Object parseFundingInterval(Object interval)
    {
        Object intervals = new java.util.HashMap<String, Object>() {{
            put( "3600000", "1h" );
            put( "14400000", "4h" );
            put( "28800000", "8h" );
            put( "57600000", "16h" );
            put( "86400000", "24h" );
        }};
        return this.safeString(intervals, interval, interval);
    }

    /**
     * @method
     * @name kucoin#fetchFundingRateHistory
     * @description fetches historical funding rate prices
     * @see https://www.kucoin.com/docs-new/rest/futures-trading/funding-fees/get-public-funding-history
     * @see https://www.kucoin.com/docs-new/rest/ua/get-history-funding-rate
     * @param {string} symbol unified symbol of the market to fetch the funding rate history for
     * @param {int} [since] not used by kucuoinfutures
     * @param {int} [limit] the maximum amount of [funding rate structures]{@link https://docs.ccxt.com/?id=funding-rate-history-structure} to fetch
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {int} [params.until] end time in ms
     * @param {boolean} [params.uta] set to true for the unified trading account (uta), defaults to true
     * @returns {object[]} a list of [funding rate structures]{@link https://docs.ccxt.com/?id=funding-rate-history-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchFundingRateHistory(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbol = Helpers.getArg(optionalArgs, 0, null);
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(symbol, null)))
            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " fetchFundingRateHistory() requires a symbol argument")) ;
            }
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "symbol", Helpers.GetValue(market, "id") );
            }};
            Object until = this.safeInteger(parameters, "until");
            Object uta = false;
            var utaparametersVariable = this.handleOptionAndParams(parameters, "fetchFundingRateHistory", "uta", uta);
            uta = ((java.util.List<Object>) utaparametersVariable).get(0);
            parameters = ((java.util.List<Object>) utaparametersVariable).get(1);
            parameters = this.omit(parameters, "until");
            Object start = since;
            Object end = until;
            if (Helpers.isTrue(Helpers.isEqual(since, null)))
            {
                start = 0;
            }
            if (Helpers.isTrue(Helpers.isEqual(until, null)))
            {
                end = this.milliseconds();
            }
            Object response = null;
            Object resultKey = "data";
            if (Helpers.isTrue(uta))
            {
                Helpers.addElementToObject(request, "startAt", start);
                Helpers.addElementToObject(request, "endAt", end);
                //
                //     {
                //         "code": "200000",
                //         "data": {
                //             "symbol": "XBTUSDTM",
                //             "list": [
                //                 {
                //                     "fundingRate": 7.6E-5,
                //                     "ts": 1706097600000
                //                 },
                //             ]
                //         }
                //     }
                //
                Object utaResponse = (this.utaGetMarketFundingRateHistory(this.extend(request, parameters))).join();
                response = this.safeDict(utaResponse, "data", new java.util.HashMap<String, Object>() {{}});
                resultKey = "list";
            } else
            {
                Helpers.addElementToObject(request, "from", start);
                Helpers.addElementToObject(request, "to", end);
                //
                //     {
                //         "code": "200000",
                //         "data": [
                //             {
                //                 "symbol": "IDUSDTM",
                //                 "fundingRate": 2.26E-4,
                //                 "timepoint": 1702296000000
                //             }
                //         ]
                //     }
                //
                response = (this.futuresPublicGetContractFundingRates(this.extend(request, parameters))).join();
            }
            Object result = this.safeList(response, resultKey, new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            return this.parseFundingRateHistories(result, market, since, limit);
        });

    }

