    public Object parseMarginModification(Object info, Object... optionalArgs)
    {
        //
        //    {
        //        "id": "62311d26064e8f00013f2c6d",
        //        "symbol": "XRPUSDTM",
        //        "autoDeposit": false,
        //        "maintMarginReq": 0.01,
        //        "riskLimit": 200000,
        //        "realLeverage": 0.88,
        //        "crossMode": false,
        //        "delevPercentage": 0.4,
        //        "openingTimestamp": 1647385894798,
        //        "currentTimestamp": 1647414510672,
        //        "currentQty": -1,
        //        "currentCost": -7.658,
        //        "currentComm": 0.0053561,
        //        "unrealisedCost": -7.658,
        //        "realisedGrossCost": 0,
        //        "realisedCost": 0.0053561,
        //        "isOpen": true,
        //        "markPrice": 0.7635,
        //        "markValue": -7.635,
        //        "posCost": -7.658,
        //        "posCross": 1.00016084,
        //        "posInit": 7.658,
        //        "posComm": 0.00979006,
        //        "posLoss": 0,
        //        "posMargin": 8.6679509,
        //        "posMaint": 0.08637006,
        //        "maintMargin": 8.6909509,
        //        "realisedGrossPnl": 0,
        //        "realisedPnl": -0.0038335,
        //        "unrealisedPnl": 0.023,
        //        "unrealisedPnlPcnt": 0.003,
        //        "unrealisedRoePcnt": 0.003,
        //        "avgEntryPrice": 0.7658,
        //        "liquidationPrice": 1.6239,
        //        "bankruptPrice": 1.6317,
        //        "settleCurrency": "USDT"
        //    }
        //
        //    {
        //        "code":"200000",
        //        "msg":"Position does not exist"
        //    }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object id = this.safeString(info, "id");
        market = this.safeMarket(id, market);
        Object currencyId = this.safeString(info, "settleCurrency");
        Object crossMode = this.safeValue(info, "crossMode");
        Object mode = ((Helpers.isTrue(crossMode))) ? "cross" : "isolated";
        Object marketId = this.safeString(market, "symbol");
        Object timestamp = this.safeInteger(info, "currentTimestamp");
        final Object finalMarket = market;
        return new java.util.HashMap<String, Object>() {{
            put( "info", info );
            put( "symbol", KucoinCore.this.safeSymbol(marketId, finalMarket) );
            put( "type", null );
            put( "marginMode", mode );
            put( "amount", null );
            put( "total", null );
            put( "code", KucoinCore.this.safeCurrencyCode(currencyId) );
            put( "status", null );
            put( "timestamp", timestamp );
            put( "datetime", KucoinCore.this.iso8601(timestamp) );
        }};
    }

    /**
     * @method
     * @name kucoin#fetchMarginMode
     * @description fetches the margin mode of a trading pair
     * @see https://www.kucoin.com/docs-new/rest/futures-trading/positions/get-margin-mode
     * @param {string} symbol unified symbol of the market to fetch the margin mode for
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a [margin mode structure]{@link https://docs.ccxt.com/?id=margin-mode-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchMarginMode(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "symbol", Helpers.GetValue(market, "id") );
            }};
            Object response = (this.futuresPrivateGetPositionGetMarginMode(this.extend(request, parameters))).join();
            //
            //     {
            //         "code": "200000",
            //         "data": {
            //             "symbol": "XBTUSDTM",
            //             "marginMode": "ISOLATED"
            //         }
            //     }
            //
            Object data = this.safeDict(response, "data", new java.util.HashMap<String, Object>() {{}});
            return this.parseMarginMode(data, market);
        });

    }

