    public Object parseADLRank(Object info, Object... optionalArgs)
    {
        //
        // fetchPositionsADLRank
        //
        //     {
        //         "id": "600000000001260912",
        //         "symbol": "XBTUSDTM",
        //         "crossMode": true,
        //         "maintMarginReq": 0.0040000133,
        //         "delevPercentage": 0.0,
        //         "openingTimestamp": 1768481882915,
        //         "currentTimestamp": 1768481897988,
        //         "currentQty": 1,
        //         "currentCost": 96.9768,
        //         "currentComm": 0.05818608,
        //         "unrealisedCost": 96.9768,
        //         "realisedGrossCost": 0.0,
        //         "realisedCost": 0.05818608,
        //         "isOpen": true,
        //         "markPrice": 96985.6,
        //         "markValue": 96.9856,
        //         "posCost": 96.9768,
        //         "posInit": 4.84884,
        //         "posMargin": 4.84928,
        //         "posMaint": 0.38794369,
        //         "realisedGrossPnl": 0.0,
        //         "realisedPnl": -0.05818608,
        //         "unrealisedPnl": 0.0088,
        //         "unrealisedPnlPcnt": 1.0E-4,
        //         "unrealisedRoePcnt": 0.0018,
        //         "avgEntryPrice": 96976.8,
        //         "liquidationPrice": 52351.69,
        //         "bankruptPrice": 52110.87,
        //         "settleCurrency": "USDT",
        //         "isInverse": false,
        //         "maintainMargin": 0.0040000133,
        //         "marginMode": "CROSS",
        //         "positionSide": "LONG",
        //         "leverage": 20,
        //         "dealComm": -0.05818608,
        //         "fundingFee": 0,
        //         "tax": 0
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(info, "symbol");
        Object timestamp = this.safeInteger(info, "openingTimestamp");
        Object percentage = this.safeString(info, "delevPercentage");
        return new java.util.HashMap<String, Object>() {{
            put( "info", info );
            put( "symbol", KucoinCore.this.safeSymbol(marketId, market, null, "contract") );
            put( "rank", null );
            put( "rating", null );
            put( "percentage", KucoinCore.this.parseNumber(Precise.stringMul(percentage, "100")) );
            put( "timestamp", timestamp );
            put( "datetime", KucoinCore.this.iso8601(timestamp) );
        }};
    }
